"use strict";parserFactory.register("re-library.com",()=>new ReLibraryParser);class ReLibraryParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(r){return[...r.querySelectorAll("div.su-accordion div.su-spoiler-content li a:not(:has(>span.rl-unlock-text))")].map(r=>util.hyperLinkToChapter(r))}getInformationEpubItemChildNodes(r){return[...r.querySelectorAll("#synopsis+div div.su-box-content")]}}